package com.example.moozik

import android.content.Intent
import android.graphics.BitmapFactory
import android.os.Bundle
import android.view.ViewGroup
import android.view.View
import android.widget.Button
import android.widget.EditText
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import com.example.moozik.util.collectEditTexts
import com.example.moozik.util.findImageViewByContentDescription
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.auth.GoogleAuthProvider
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext

class LoginActivity : AppCompatActivity() {

    private val auth by lazy { FirebaseAuth.getInstance() }
    private val googleSignInClient: GoogleSignInClient by lazy {
        val webClientId = getString(R.string.default_web_client_id)
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(webClientId)
            .requestEmail()
            .build()
        GoogleSignIn.getClient(this, gso)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        auth.currentUser?.let { currentUser ->
            startActivity(
                Intent(this, MainActivity::class.java)
                    .putExtra(MainActivity.EXTRA_START_SCREEN, MainActivity.DESTINATION_STORE)
                    .putExtra(MainActivity.EXTRA_USER_NAME, currentUser.displayName ?: currentUser.email?.substringBefore("@") ?: "Guest User")
            )
            finish()
            return
        }

        setContentView(R.layout.activity_login)

        val btnLogin = findViewById<Button>(R.id.btnLogin)
        val btnNoAccount = findViewById<TextView>(R.id.btnNoAccount)
        val logo = findViewById<ImageView>(R.id.ivAuthLogoLogin)
        val editTexts = findViewById<ViewGroup>(android.R.id.content).collectEditTexts()
        val emailInput = findViewById<EditText>(R.id.editLoginEmail)
        val passwordInput = editTexts.getOrNull(1)
        val googleButton = findViewById<ViewGroup>(android.R.id.content).findImageViewByContentDescription("Google")

        try {
            assets.open("logo.png").use { stream ->
                logo.setImageBitmap(BitmapFactory.decodeStream(stream))
            }
        } catch (_: Exception) {
            // Keep XML fallback drawable.
        }

        btnLogin.setOnClickListener {
            val enteredEmail = emailInput.text?.toString()?.trim().orEmpty()
            val enteredPassword = passwordInput?.text?.toString()?.trim().orEmpty()

            if (enteredEmail.isBlank() || enteredPassword.isBlank()) {
                android.widget.Toast.makeText(this, "Email or password cannot be empty", android.widget.Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            lifecycleScope.launch(Dispatchers.IO) {
                try {
                    auth.signInWithEmailAndPassword(enteredEmail, enteredPassword).await()
                    val userName = auth.currentUser?.displayName
                        ?: enteredEmail.substringBefore("@").ifBlank { "Guest User" }
                    withContext(Dispatchers.Main) {
                        startActivity(
                            Intent(this@LoginActivity, MainActivity::class.java)
                                .putExtra(MainActivity.EXTRA_START_SCREEN, MainActivity.DESTINATION_STORE)
                                .putExtra(MainActivity.EXTRA_USER_NAME, userName)
                        )
                        finish()
                    }
                } catch (e: Exception) {
                    withContext(Dispatchers.Main) {
                        android.widget.Toast.makeText(this@LoginActivity, e.message ?: "Login failed", android.widget.Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }

        btnNoAccount.setOnClickListener {
            // Navigate to Signup
            startActivity(Intent(this, SignupActivity::class.java))
        }

        googleButton?.setOnClickListener {
            startActivityForResult(googleSignInClient.signInIntent, RC_GOOGLE_SIGN_IN)
        }
        (googleButton?.parent as? View)?.setOnClickListener {
            startActivityForResult(googleSignInClient.signInIntent, RC_GOOGLE_SIGN_IN)
        }
    }

    @Deprecated("Deprecated in Java")
    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        if (requestCode != RC_GOOGLE_SIGN_IN) return

        try {
            val task = GoogleSignIn.getSignedInAccountFromIntent(data)
            val account = task.getResult(ApiException::class.java)
            if (account == null) {
                android.widget.Toast.makeText(this, "Google sign-in failed", android.widget.Toast.LENGTH_SHORT).show()
                return
            }

            handleGoogleAccount(account)
        } catch (e: Exception) {
            android.widget.Toast.makeText(this, e.message ?: "Google sign-in failed", android.widget.Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleGoogleAccount(account: GoogleSignInAccount) {
        val idToken = account.idToken
        if (idToken.isNullOrBlank()) {
            android.widget.Toast.makeText(this, "Google account missing token", android.widget.Toast.LENGTH_SHORT).show()
            return
        }

        lifecycleScope.launch(Dispatchers.IO) {
            try {
                val credential = GoogleAuthProvider.getCredential(idToken, null)
                auth.signInWithCredential(credential).await()
                val userName = auth.currentUser?.displayName
                    ?: auth.currentUser?.email?.substringBefore("@")
                    ?: account.email?.substringBefore("@")
                    ?: "Guest User"
                withContext(Dispatchers.Main) {
                    startActivity(
                        Intent(this@LoginActivity, MainActivity::class.java)
                            .putExtra(MainActivity.EXTRA_START_SCREEN, MainActivity.DESTINATION_STORE)
                            .putExtra(MainActivity.EXTRA_USER_NAME, userName)
                    )
                    finish()
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    android.widget.Toast.makeText(this@LoginActivity, e.message ?: "Google sign-in failed", android.widget.Toast.LENGTH_SHORT).show()
                }
            }
        }
    }

    companion object {
        private const val RC_GOOGLE_SIGN_IN = 9001
    }
}

package com.example.moozik

import android.content.Intent
import android.graphics.BitmapFactory
import android.os.Bundle
import android.view.ViewGroup
import android.view.View
import android.widget.Button
import android.widget.EditText
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import com.example.moozik.util.collectEditTexts
import com.example.moozik.util.findImageViewByContentDescription
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.auth.GoogleAuthProvider
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext

class LoginActivity : AppCompatActivity() {

    private val auth by lazy { FirebaseAuth.getInstance() }
    private val googleSignInClient: GoogleSignInClient by lazy {
        val webClientId = getString(R.string.default_web_client_id)
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(webClientId)
            .requestEmail()
            .build()
        GoogleSignIn.getClient(this, gso)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        auth.currentUser?.let { currentUser ->
            startActivity(
                Intent(this, MainActivity::class.java)
                    .putExtra(MainActivity.EXTRA_START_SCREEN, MainActivity.DESTINATION_STORE)
                    .putExtra(MainActivity.EXTRA_USER_NAME, currentUser.displayName ?: currentUser.email?.substringBefore("@") ?: "Guest User")
            )
            finish()
            return
        }

        setContentView(R.layout.activity_login)

        val btnLogin = findViewById<Button>(R.id.btnLogin)
        val btnNoAccount = findViewById<TextView>(R.id.btnNoAccount)
        val logo = findViewById<ImageView>(R.id.ivAuthLogoLogin)
        val editTexts = findViewById<ViewGroup>(android.R.id.content).collectEditTexts()
        val emailInput = findViewById<EditText>(R.id.editLoginEmail)
        val passwordInput = editTexts.getOrNull(1)
        val googleButton = findViewById<ViewGroup>(android.R.id.content).findImageViewByContentDescription("Google")

        try {
            assets.open("logo.png").use { stream ->
                logo.setImageBitmap(BitmapFactory.decodeStream(stream))
            }
        } catch (_: Exception) {
            // Keep XML fallback drawable.
        }

        btnLogin.setOnClickListener {
            val enteredEmail = emailInput.text?.toString()?.trim().orEmpty()
            val enteredPassword = passwordInput?.text?.toString()?.trim().orEmpty()

            if (enteredEmail.isBlank() || enteredPassword.isBlank()) {
                android.widget.Toast.makeText(this, "Email or password cannot be empty", android.widget.Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            lifecycleScope.launch(Dispatchers.IO) {
                try {
                    auth.signInWithEmailAndPassword(enteredEmail, enteredPassword).await()
                    saveUserProfileToFirestore(
                        displayName = auth.currentUser?.displayName ?: enteredEmail.substringBefore("@").ifBlank { "Guest User" }
                    )
                    val userName = auth.currentUser?.displayName
                        ?: enteredEmail.substringBefore("@").ifBlank { "Guest User" }
                    withContext(Dispatchers.Main) {
                        startActivity(
                            Intent(this@LoginActivity, MainActivity::class.java)
                                .putExtra(MainActivity.EXTRA_START_SCREEN, MainActivity.DESTINATION_STORE)
                                .putExtra(MainActivity.EXTRA_USER_NAME, userName)
                        )
                        finish()
                    }
                } catch (e: Exception) {
                    withContext(Dispatchers.Main) {
                        android.widget.Toast.makeText(this@LoginActivity, e.message ?: "Login failed", android.widget.Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }

        btnNoAccount.setOnClickListener {
            // Navigate to Signup
            startActivity(Intent(this, SignupActivity::class.java))
        }

        googleButton?.setOnClickListener {
            startActivityForResult(googleSignInClient.signInIntent, RC_GOOGLE_SIGN_IN)
        }
        (googleButton?.parent as? View)?.setOnClickListener {
            startActivityForResult(googleSignInClient.signInIntent, RC_GOOGLE_SIGN_IN)
        }
    }

    @Deprecated("Deprecated in Java")
    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        if (requestCode != RC_GOOGLE_SIGN_IN) return

        try {
            val task = GoogleSignIn.getSignedInAccountFromIntent(data)
            val account = task.getResult(ApiException::class.java)
            if (account == null) {
                android.widget.Toast.makeText(this, "Google sign-in failed", android.widget.Toast.LENGTH_SHORT).show()
                return
            }

            handleGoogleAccount(account)
        } catch (e: Exception) {
            android.widget.Toast.makeText(this, e.message ?: "Google sign-in failed", android.widget.Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleGoogleAccount(account: GoogleSignInAccount) {
        val idToken = account.idToken
        if (idToken.isNullOrBlank()) {
            android.widget.Toast.makeText(this, "Google account missing token", android.widget.Toast.LENGTH_SHORT).show()
            return
        }

        lifecycleScope.launch(Dispatchers.IO) {
            try {
                val credential = GoogleAuthProvider.getCredential(idToken, null)
                auth.signInWithCredential(credential).await()
                saveUserProfileToFirestore(
                    displayName = auth.currentUser?.displayName
                        ?: auth.currentUser?.email?.substringBefore("@")
                        ?: account.email?.substringBefore("@")
                        ?: "Guest User"
                )
                val userName = auth.currentUser?.displayName
                    ?: auth.currentUser?.email?.substringBefore("@")
                    ?: account.email?.substringBefore("@")
                    ?: "Guest User"
                withContext(Dispatchers.Main) {
                    startActivity(
                        Intent(this@LoginActivity, MainActivity::class.java)
                            .putExtra(MainActivity.EXTRA_START_SCREEN, MainActivity.DESTINATION_STORE)
                            .putExtra(MainActivity.EXTRA_USER_NAME, userName)
                    )
                    finish()
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    android.widget.Toast.makeText(this@LoginActivity, e.message ?: "Google sign-in failed", android.widget.Toast.LENGTH_SHORT).show()
                }
            }
        }
    }

    companion object {
        private const val RC_GOOGLE_SIGN_IN = 9001
    }

    private suspend fun saveUserProfileToFirestore(displayName: String) {
        val firebaseUser = auth.currentUser ?: return
        try {
            FirebaseFirestore.getInstance()
                .collection("users")
                .document(firebaseUser.uid)
                .set(
                    hashMapOf<String, Any?>(
                        "name" to displayName,
                        "email" to firebaseUser.email,
                        "userId" to firebaseUser.uid
                    )
                )
                .await()
        } catch (e: Exception) {
            withContext(Dispatchers.Main) {
                android.widget.Toast.makeText(this@LoginActivity, e.message ?: "Failed to save user profile", android.widget.Toast.LENGTH_SHORT).show()
            }
        }
    }
}

package com.example.moozik

import android.os.Build
import android.os.Bundle
import android.graphics.Rect
import android.view.View
import android.widget.Button
import android.widget.ImageView
import android.widget.TextView
import androidx.lifecycle.lifecycleScope
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import com.example.moozik.data.CartStore
import com.example.moozik.adapters.ProductAdapter
import com.example.moozik.util.loadProductImage
import com.example.moozik.data.ProductRepository
import com.example.moozik.models.Product
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

class ProductFragments {

    class ProductDetailFragment : BaseScreenFragment(R.layout.fragment_product_detail) {

        override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
            super.onViewCreated(view, savedInstanceState)

            val btnBack = view.findViewById<ImageView>(R.id.btnBack)
            btnBack.setOnClickListener { parentFragmentManager.popBackStack() }

            val btnCart = view.findViewById<ImageView>(R.id.btnCart)
            btnCart.setOnClickListener {
                navigateTo(CartFragment())
            }

            val btnShare = view.findViewById<ImageView>(R.id.btnShare)
            btnShare.setOnClickListener {
                android.widget.Toast.makeText(requireContext(), "Share product", android.widget.Toast.LENGTH_SHORT).show()
            }

            val product = readProductFromArgs() ?: return

            view.findViewById<TextView>(R.id.textProductTitle).text = product.name
            view.findViewById<TextView>(R.id.textProductRating).text = "Rating: ${product.rating}"
            view.findViewById<TextView>(R.id.textProductPrice).text = product.price
            view.findViewById<TextView>(R.id.textProductDescription).text = product.description
            // Append provided detailed Schecter description if available (or always append to ensure content)
            val extraDesc = "Schecter Synyster Gates Custom-S: The Ultimate Shred Machine\nTake your playing to the front lines with the Schecter Synyster Gates Custom-S. Designed specifically for the high-octane demands of Avenged Sevenfold’s lead guitarist, this isn't just a signature model—it’s a precision-engineered weapon for modern metal. Featuring the iconic pinstripe aesthetic and the revolutionary Sustainiac® system, this guitar is built for players who refuse to be limited by physics.\nKey Features\nInfinite Sustain with Sustainiac®: The secret to Syn’s haunting leads. The neck pickup doubles as a Sustainiac driver, allowing you to hold notes indefinitely with three modes: Fundamental, Harmonic, or a blend of both.\nSchecter USA Signature Pickups: In the bridge, you’ll find the hand-wound USA Synyster Gates Signature humbucker. Built with Ceramic-8 magnets, it delivers crushing output without sacrificing clarity or articulation.\nUltra-Fast Playing Profile: The 3-piece mahogany neck features an Ultra Thin ‘C’ profile and a 16” radius ebony fingerboard. Whether you’re sweeping through arpeggios or digging into heavy riffs, the neck feel is effortless.\nFloyd Rose 1500 Series Bridge: Dive bomb, squeal, and flutter with total confidence. The upgraded 1500 Series bridge offers stainless steel hardware and a push-in arm for superior tuning stability and a smoother feel than standard systems.\nIconic \"Avenger\" Body Shape: Crafted from solid mahogany, the distinctive Avenger body provides a deep, resonant low-end and incredible upper-fret access thanks to the Ultra Access neck joint.\nTechnical Specifications\nBody Material: Mahogany\nNeck Material: 3-pc Mahogany with Carbon Fiber Reinforcement Rods\nFretboard: Ebony with Pearloid \"SYN\" and \"Death Bat\" Inlays\nFrets: 24 X-Jumbo\nBridge Pickup: Schecter USA Synyster Gates Signature Humbucker\nNeck Pickup: Sustainiac®\nControls: Volume/Tone/3-Way (Pickup) Switch/2-Way On-Off Sustainiac Switch/3-Way Sustainiac Mode Switch\nScale Length: 25.5\" (648mm)"

            // Append the extra description after the product description so it's visible under Description title
            val descView = view.findViewById<TextView>(R.id.textProductDescription)
            descView.text = product.description + "\n\n" + extraDesc

            val img = view.findViewById<ImageView>(R.id.imageProductLarge)
            img.loadProductImage(product, R.drawable.ic_image)

            val similarRecycler = view.findViewById<RecyclerView>(R.id.recyclerSimilarProducts)
            val related = ProductRepository.relatedProducts(product)
            similarRecycler.layoutManager = LinearLayoutManager(requireContext(), LinearLayoutManager.HORIZONTAL, false)
            similarRecycler.adapter = ProductAdapter(related) { relatedProduct ->
                navigateTo(newInstance(relatedProduct), addToBackStack = true)
            }
            val spacing = resources.getDimensionPixelSize(R.dimen.catalog_card_spacing)
            similarRecycler.addItemDecoration(object : RecyclerView.ItemDecoration() {
                override fun getItemOffsets(outRect: Rect, view: View, parent: RecyclerView, state: RecyclerView.State) {
                    outRect.right = spacing / 2
                }
            })
            similarRecycler.visibility = if (related.isEmpty()) View.GONE else View.VISIBLE

            view.findViewById<Button>(R.id.btnBuyNow).setOnClickListener {
                // Since there's no backend, show simple feedback using navigation or a Toast
                android.widget.Toast.makeText(requireContext(), "Buy Now: ${product.name}", android.widget.Toast.LENGTH_SHORT).show()
            }

            view.findViewById<Button>(R.id.btnAddCart).setOnClickListener {
                viewLifecycleOwner.lifecycleScope.launch(Dispatchers.Main) {
                    CartStore.addToCart(requireContext(), product)
                    android.widget.Toast.makeText(requireContext(), "Added to cart: ${product.name}", android.widget.Toast.LENGTH_SHORT).show()
                }
            }

            view.findViewById<ImageView>(R.id.btnChatSeller).setOnClickListener {
                android.widget.Toast.makeText(requireContext(), "Chat with seller (mock)", android.widget.Toast.LENGTH_SHORT).show()
            }
        }

        private fun readProductFromArgs(): Product? {
            val args = arguments ?: return null
            return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                args.getParcelable(ARG_PRODUCT, Product::class.java)
            } else {
                @Suppress("DEPRECATION")
                args.getParcelable(ARG_PRODUCT)
            }
        }

        companion object {
                private const val ARG_PRODUCT = "arg_product"

                fun newInstance(product: Product): ProductDetailFragment {
                    return ProductDetailFragment().apply {
                        arguments = Bundle().apply {
                            putParcelable(ARG_PRODUCT, product)
                        }
                    }
                }
        }
    }
}

package com.example.moozik

import android.os.Build
import android.os.Bundle
import android.graphics.Rect
import android.view.View
