    private var currentQuery: String = ""
    private var cartListenerRegistration: ListenerRegistration? = null

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        val userId = FirebaseAuth.getInstance().currentUser?.uid
        if (!userId.isNullOrBlank()) {
            cartListenerRegistration = FirestoreCartRepository().listenToCart(userId) { remoteItems ->
                viewLifecycleOwner.lifecycleScope.launch(Dispatchers.IO) {
                    CartStore.replaceCartItemsFromFirestore(requireContext(), remoteItems)
                    withContext(Dispatchers.Main) {
                        renderCart(view, currentQuery)
                    }
                }
            }
        }

        renderCart(view, currentQuery)

        bindBottomNav(
            root = view,
            selectedIndex = 2,
            onStore = {
                navigateTo(
                    StoreFragment.newInstance(
                        requireActivity().intent.getStringExtra(MainActivity.EXTRA_USER_NAME)
                            ?: "Guest User"
                    )
                )
            },
            onLessons = { navigateTo(LessonsFragment()) },
            onCart = { },
            onProfile = { navigateTo(ProfileFragment()) }
        )
    }

    private fun renderCart(root: View, query: String = currentQuery) {
        currentQuery = query
        viewLifecycleOwner.lifecycleScope.launch(Dispatchers.Main) {
            val items = CartStore.getCartItems(requireContext(), query)

            val recycler = root.findViewById<RecyclerView>(R.id.recyclerCartItems)
            recycler.layoutManager = LinearLayoutManager(requireContext())
            recycler.adapter = CartAdapter(items) { cartItem ->
                viewLifecycleOwner.lifecycleScope.launch(Dispatchers.IO) {
                    CartStore.removeOneFromCart(requireContext(), cartItem.product.id)
                    val userId = FirebaseAuth.getInstance().currentUser?.uid
                    if (!userId.isNullOrBlank()) {
                        FirestoreCartRepository().removeByProductId(userId, cartItem.product.id)
                    }
                    withContext(Dispatchers.Main) {
                        renderCart(root, currentQuery)
                    }
                }
            }

            val subtotal = CartStore.getSubtotal(requireContext(), query)
            val shipping = if (items.isEmpty()) 0 else 500
            val total = subtotal + shipping

            root.findViewById<TextView>(R.id.textSubtotalValue).text = formatPkr(subtotal)
            root.findViewById<TextView>(R.id.textShippingValue).text = formatPkr(shipping)
            root.findViewById<TextView>(R.id.textTotalValue).text = formatPkr(total)
            root.findViewById<TextView>(R.id.textEmptyCart).apply {
                text = if (query.isNotBlank() && items.isEmpty()) "No matching items" else "Your cart is empty"
                visibility = if (items.isEmpty()) View.VISIBLE else View.GONE
            }
        }
    }

    private fun formatPkr(value: Int): String {
        return "PKR ${"%,d".format(value)}"
    }

    private fun parsePrice(value: String): Int {
        return value.filter { it.isDigit() }.toIntOrNull() ?: 0
    }

    override fun onDestroyView() {
        cartListenerRegistration?.remove()
        cartListenerRegistration = null
        super.onDestroyView()
    }
}

class ProfileFragment : BaseScreenFragment(R.layout.activity_profile) {
    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        view.findViewById<ImageView>(R.id.imgAvatarProfile).loadAssetImage("accountimage.jpg", R.drawable.ic_avatar)

        bindBottomNav(
            root = view,
            selectedIndex = 3,
            onStore = {
                navigateTo(
                    StoreFragment.newInstance(
                        requireActivity().intent.getStringExtra(MainActivity.EXTRA_USER_NAME)
                            ?: "Guest User"
                    )
                )
            },
            onLessons = { navigateTo(LessonsFragment()) },
            onCart = { navigateTo(CartFragment()) },
            onProfile = { }
        )
    }
}

package com.example.moozik

import android.content.Intent
import android.graphics.BitmapFactory
import android.os.Bundle
import android.view.ViewGroup
import android.widget.Button
import android.widget.EditText
import android.widget.ImageView
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import com.example.moozik.util.collectEditTexts
import com.google.firebase.auth.FirebaseAuth
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext

class SignupActivity : AppCompatActivity() {

    private val auth by lazy { FirebaseAuth.getInstance() }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_signup)

        val btnSignup = findViewById<Button>(R.id.btnSignup)
        val usernameInput = findViewById<EditText>(R.id.editSignupUsername)
        val logo = findViewById<ImageView>(R.id.ivAuthLogoSignup)
        val editTexts = findViewById<ViewGroup>(android.R.id.content).collectEditTexts()
        val emailInput = editTexts.getOrNull(1)
        val passwordInput = editTexts.getOrNull(2)
        val confirmPasswordInput = editTexts.getOrNull(3)

        try {
            assets.open("logo.png").use { stream ->
                logo.setImageBitmap(BitmapFactory.decodeStream(stream))
            }
        } catch (_: Exception) {
            // Keep XML fallback drawable.
        }

        btnSignup.setOnClickListener {
            val enteredUserName = usernameInput.text?.toString()?.trim().orEmpty()
            val enteredEmail = emailInput?.text?.toString()?.trim().orEmpty()
            val enteredPassword = passwordInput?.text?.toString()?.trim().orEmpty()
            val confirmPassword = confirmPasswordInput?.text?.toString()?.trim().orEmpty()

            if (enteredEmail.isBlank() || enteredPassword.isBlank()) {
                android.widget.Toast.makeText(this, "Email or password cannot be empty", android.widget.Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            if (confirmPasswordInput != null && confirmPassword.isNotBlank() && enteredPassword != confirmPassword) {
                android.widget.Toast.makeText(this, "Passwords do not match", android.widget.Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            lifecycleScope.launch(Dispatchers.IO) {
                try {
                    auth.createUserWithEmailAndPassword(enteredEmail, enteredPassword).await()
                    val userName = enteredUserName.ifBlank { enteredEmail.substringBefore("@").ifBlank { "Guest User" } }
                    withContext(Dispatchers.Main) {
                        startActivity(
                            Intent(this@SignupActivity, MainActivity::class.java)
                                .putExtra(MainActivity.EXTRA_START_SCREEN, MainActivity.DESTINATION_STORE)
                                .putExtra(MainActivity.EXTRA_USER_NAME, userName)
                        )
                        finish()
                    }
                } catch (e: Exception) {
                    withContext(Dispatchers.Main) {
                        android.widget.Toast.makeText(this@SignupActivity, e.message ?: "Signup failed", android.widget.Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }
    }
}

package com.example.moozik

import android.content.Intent
import android.graphics.BitmapFactory
import android.os.Bundle
import android.view.ViewGroup
import android.widget.Button
import android.widget.EditText
import android.widget.ImageView
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import com.example.moozik.util.collectEditTexts
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext

class SignupActivity : AppCompatActivity() {

    private val auth by lazy { FirebaseAuth.getInstance() }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_signup)

        val btnSignup = findViewById<Button>(R.id.btnSignup)
        val usernameInput = findViewById<EditText>(R.id.editSignupUsername)
        val logo = findViewById<ImageView>(R.id.ivAuthLogoSignup)
        val editTexts = findViewById<ViewGroup>(android.R.id.content).collectEditTexts()
        val emailInput = editTexts.getOrNull(1)
        val passwordInput = editTexts.getOrNull(2)
        val confirmPasswordInput = editTexts.getOrNull(3)

        try {
            assets.open("logo.png").use { stream ->
                logo.setImageBitmap(BitmapFactory.decodeStream(stream))
            }
        } catch (_: Exception) {
            // Keep XML fallback drawable.
        }

        btnSignup.setOnClickListener {
            val enteredUserName = usernameInput.text?.toString()?.trim().orEmpty()
            val enteredEmail = emailInput?.text?.toString()?.trim().orEmpty()
            val enteredPassword = passwordInput?.text?.toString()?.trim().orEmpty()
            val confirmPassword = confirmPasswordInput?.text?.toString()?.trim().orEmpty()

            if (enteredEmail.isBlank() || enteredPassword.isBlank()) {
                android.widget.Toast.makeText(this, "Email or password cannot be empty", android.widget.Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            if (confirmPasswordInput != null && confirmPassword.isNotBlank() && enteredPassword != confirmPassword) {
                android.widget.Toast.makeText(this, "Passwords do not match", android.widget.Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            lifecycleScope.launch(Dispatchers.IO) {
                try {
                    auth.createUserWithEmailAndPassword(enteredEmail, enteredPassword).await()
                    saveUserProfileToFirestore(
                        displayName = enteredUserName.ifBlank { enteredEmail.substringBefore("@").ifBlank { "Guest User" } }
                    )
                    val userName = enteredUserName.ifBlank { enteredEmail.substringBefore("@").ifBlank { "Guest User" } }
                    withContext(Dispatchers.Main) {
                        startActivity(
                            Intent(this@SignupActivity, MainActivity::class.java)
                                .putExtra(MainActivity.EXTRA_START_SCREEN, MainActivity.DESTINATION_STORE)
                                .putExtra(MainActivity.EXTRA_USER_NAME, userName)
                        )
                        finish()
                    }
                } catch (e: Exception) {
                    withContext(Dispatchers.Main) {
                        android.widget.Toast.makeText(this@SignupActivity, e.message ?: "Signup failed", android.widget.Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }
    }

    private suspend fun saveUserProfileToFirestore(displayName: String) {
        val firebaseUser = auth.currentUser ?: return
        try {
            FirebaseFirestore.getInstance()
                .collection("users")
                .document(firebaseUser.uid)
                .set(
                    hashMapOf<String, Any?>(
                        "name" to displayName,
                        "email" to firebaseUser.email,
                        "userId" to firebaseUser.uid
                    )
                )
                .await()
        } catch (e: Exception) {
            withContext(Dispatchers.Main) {
                android.widget.Toast.makeText(this@SignupActivity, e.message ?: "Failed to save user profile", android.widget.Toast.LENGTH_SHORT).show()
            }
        }
    }
}

package com.example.moozik.data

import android.content.ContentValues
import android.content.Context
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteOpenHelper
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import com.example.moozik.models.CartItem
import com.example.moozik.models.Product

private const val DB_NAME = "moozik_store.db"
private const val DB_VERSION = 1

private const val TABLE_PRODUCTS = "products"
private const val TABLE_CART_ITEMS = "cart_items"

private const val COL_PRODUCT_ID = "product_id"
private const val COL_TITLE = "title"
private const val COL_CATEGORY = "category"
private const val COL_PRICE = "price"
private const val COL_RATING = "rating"
private const val COL_DESCRIPTION = "description"
private const val COL_IMAGE_ASSET = "image_asset"
private const val COL_QUANTITY = "quantity"

class MoozikDatabaseHelper(context: Context) : SQLiteOpenHelper(
    context,
    DB_NAME,
    null,
    DB_VERSION
) {
    override fun onConfigure(db: SQLiteDatabase) {
        super.onConfigure(db)
        db.setForeignKeyConstraintsEnabled(true)
    }

    override fun onCreate(db: SQLiteDatabase) {
        db.execSQL(
            """
            CREATE TABLE $TABLE_PRODUCTS (
                $COL_PRODUCT_ID TEXT PRIMARY KEY,
                $COL_TITLE TEXT NOT NULL,
                $COL_CATEGORY TEXT NOT NULL,
                $COL_PRICE TEXT NOT NULL,
                $COL_RATING REAL NOT NULL,
                $COL_DESCRIPTION TEXT NOT NULL,
                $COL_IMAGE_ASSET TEXT
            )
            """.trimIndent()
        )

        db.execSQL(
            """
            CREATE TABLE $TABLE_CART_ITEMS (
                _id INTEGER PRIMARY KEY AUTOINCREMENT,
                $COL_PRODUCT_ID TEXT NOT NULL UNIQUE,
                $COL_QUANTITY INTEGER NOT NULL DEFAULT 1,
                FOREIGN KEY($COL_PRODUCT_ID) REFERENCES $TABLE_PRODUCTS($COL_PRODUCT_ID) ON DELETE CASCADE
            )
            """.trimIndent()
        )
    }

    override fun onUpgrade(db: SQLiteDatabase, oldVersion: Int, newVersion: Int) {
        db.execSQL("DROP TABLE IF EXISTS $TABLE_CART_ITEMS")
        db.execSQL("DROP TABLE IF EXISTS $TABLE_PRODUCTS")
        onCreate(db)
    }
}

object CartStore {

    suspend fun addToCart(context: Context, product: Product, quantity: Int = 1) = withContext(Dispatchers.IO) {
        if (quantity <= 0) return@withContext
        val db = helper(context).writableDatabase
        db.beginTransaction()
        try {
            upsertProduct(db, product)

            val currentQuantity = getCartQuantity(db, product.id)
            if (currentQuantity == null) {
                val values = ContentValues().apply {
                    put(COL_PRODUCT_ID, product.id)
                    put(COL_QUANTITY, quantity)
                }
                db.insert(TABLE_CART_ITEMS, null, values)
            } else {
                updateQuantity(db, product.id, currentQuantity + quantity)
            }

            db.setTransactionSuccessful()
        } finally {
            db.endTransaction()
            db.close()
        }
    }

    suspend fun removeOneFromCart(context: Context, productId: String) = withContext(Dispatchers.IO) {
        val db = helper(context).writableDatabase
        db.beginTransaction()
        try {
            val currentQuantity = getCartQuantity(db, productId)
            when {
                currentQuantity == null -> Unit
                currentQuantity > 1 -> updateQuantity(db, productId, currentQuantity - 1)
                else -> db.delete(TABLE_CART_ITEMS, "$COL_PRODUCT_ID = ?", arrayOf(productId))
            }
            db.setTransactionSuccessful()
        } finally {
            db.endTransaction()
            db.close()
        }
    }

    suspend fun setQuantity(context: Context, productId: String, quantity: Int) = withContext(Dispatchers.IO) {
        val db = helper(context).writableDatabase
        db.beginTransaction()
        try {
            if (quantity <= 0) {
                db.delete(TABLE_CART_ITEMS, "$COL_PRODUCT_ID = ?", arrayOf(productId))
            } else {
                updateQuantity(db, productId, quantity)
            }
            db.setTransactionSuccessful()
        } finally {
            db.endTransaction()
            db.close()
        }
    }

    suspend fun getCartItems(context: Context, query: String = ""): List<CartItem> = withContext(Dispatchers.IO) {
        val db = helper(context).writableDatabase
        try {
            val normalized = query.trim()
            val sql = buildString {
                append(
                    """
                    SELECT p.$COL_PRODUCT_ID, p.$COL_TITLE, p.$COL_CATEGORY, p.$COL_PRICE,
                           p.$COL_RATING, p.$COL_DESCRIPTION, p.$COL_IMAGE_ASSET,
                           ci.$COL_QUANTITY
                    FROM $TABLE_CART_ITEMS ci
                    INNER JOIN $TABLE_PRODUCTS p ON p.$COL_PRODUCT_ID = ci.$COL_PRODUCT_ID
                    """.trimIndent()
                )
                if (normalized.isNotBlank()) {
                    append(" WHERE LOWER(p.$COL_TITLE) LIKE ? OR LOWER(p.$COL_CATEGORY) LIKE ?")
                }
                append(" ORDER BY ci._id DESC")
            }

            val selectionArgs = if (normalized.isBlank()) {
                null
            } else {
                val like = "%${normalized.lowercase()}%"
                arrayOf(like, like)
            }

            val items = mutableListOf<CartItem>()
            db.rawQuery(sql, selectionArgs).use { cursor ->
                val idIndex = cursor.getColumnIndexOrThrow(COL_PRODUCT_ID)
                val titleIndex = cursor.getColumnIndexOrThrow(COL_TITLE)
                val categoryIndex = cursor.getColumnIndexOrThrow(COL_CATEGORY)
                val priceIndex = cursor.getColumnIndexOrThrow(COL_PRICE)
                val ratingIndex = cursor.getColumnIndexOrThrow(COL_RATING)
                val descriptionIndex = cursor.getColumnIndexOrThrow(COL_DESCRIPTION)
                val quantityIndex = cursor.getColumnIndexOrThrow(COL_QUANTITY)

                while (cursor.moveToNext()) {
                    val product = Product(
                        id = cursor.getString(idIndex) ?: "",
                        name = cursor.getString(titleIndex) ?: "",
                        price = cursor.getString(priceIndex) ?: "",
                        category = cursor.getString(categoryIndex) ?: "",
                        rating = cursor.getString(ratingIndex) ?: "0.0",
                        description = cursor.getString(descriptionIndex) ?: "",
                        imageUrl = cursor.getString(cursor.getColumnIndexOrThrow(COL_IMAGE_ASSET)) ?: ""
                    )
                    items.add(
                        CartItem(
                            product = product,
                            quantity = cursor.getInt(quantityIndex)
                        )
                    )
                }
            }
            items
        } finally {
            db.close()
        }
    }

    suspend fun getSubtotal(context: Context, query: String = ""): Int {
        return getCartItems(context, query).sumOf { parsePrice(it.product.price) * it.quantity }
    }

    private fun helper(context: Context): MoozikDatabaseHelper {
        return MoozikDatabaseHelper(context.applicationContext)
    }

    private fun upsertProduct(db: SQLiteDatabase, product: Product) {
        val values = ContentValues().apply {
            put(COL_PRODUCT_ID, product.id)
            put(COL_TITLE, product.name)
            put(COL_CATEGORY, product.category)
            put(COL_PRICE, product.price)
            put(COL_RATING, product.rating)
            put(COL_DESCRIPTION, product.description)
            put(COL_IMAGE_ASSET, product.imageUrl)
        }
        db.insertWithOnConflict(TABLE_PRODUCTS, null, values, SQLiteDatabase.CONFLICT_IGNORE)
    }

    private fun getCartQuantity(db: SQLiteDatabase, productId: String): Int? {
        db.rawQuery(
            "SELECT $COL_QUANTITY FROM $TABLE_CART_ITEMS WHERE $COL_PRODUCT_ID = ?",
            arrayOf(productId)
        ).use { cursor ->
            return if (cursor.moveToFirst()) cursor.getInt(0) else null
        }
    }

    private fun updateQuantity(db: SQLiteDatabase, productId: String, quantity: Int) {
        val values = ContentValues().apply {
            put(COL_QUANTITY, quantity)
        }
        db.update(TABLE_CART_ITEMS, values, "$COL_PRODUCT_ID = ?", arrayOf(productId))
    }

    private fun parsePrice(value: String): Int {
        return value.filter { it.isDigit() }.toIntOrNull() ?: 0
    }
}

